--

CREATE FUNCTION public.create_admin(p_name character varying, p_email character varying, p_password_hash character varying, p_api_key character varying, p_api_secret text, p_webhook_secret character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    new_id UUID;
BEGIN
    INSERT INTO merchants (id, name, email, password_hash, api_key, api_secret, webhook_secret, is_active, is_admin, daily_limit)
    VALUES (uuid_generate_v4(), p_name, p_email, p_password_hash, p_api_key, p_api_secret, p_webhook_secret, true, true, 999999999999)
    RETURNING id INTO new_id;
    RETURN new_id;
END;
$$;


